#include <stdio.h>
#include <stdlib.h>
#include <math.h>


int main(void)
{
//long int i,j;

long long int a,b; scanf("%lld",&a); scanf("%lld",&b);

long long int count=0;


while(a!=b)
{

if(a>b)
{
count += a/b;
a=a%b;

if(a==0)
break;
}

if(b>a)
{
count += b/a;
b=b%a;

if(b==0)
break;
}

}

printf("%lld",count);

return 0;
}

